'use client'

import PageLayout from '@/components/layout/PageLayout'
import MetricsDashboard from '@/components/farm/MetricsDashboard'
import dynamic from 'next/dynamic'
import { motion } from 'framer-motion'
import Link from 'next/link'
import { TrendingUp, Cpu, Calculator, Database } from 'lucide-react'

const DataHealthWidget = dynamic(() => import('@/components/ml/DataHealthWidget'), { ssr: false })


import { useEffect, useState } from 'react';

export default function DashboardPage() {
  // Load farm profile from localStorage if available
  const [metrics, setMetrics] = useState({
    totalArea: 2.5,
    plantedArea: 2.0,
    treeDensity: 120,
    ler: 1.85,
    waterSavings: 68,
    carbonSequestration: 2.4,
    expectedYield: [],
    totalRevenue: 120000,
    roi: 35,
    rootOverlapIndex: 0.28,
    canopyCover: 92,
  });
  const [farmProfile, setFarmProfile] = useState<any>(null);

  useEffect(() => {
    if (typeof window !== 'undefined') {
      const stored = localStorage.getItem('multisow_farm_profile');
      if (stored) {
        const farm = JSON.parse(stored);
        setFarmProfile(farm);
        // Map farm profile to metrics (simple mapping, can be extended)
        setMetrics((prev) => ({
          ...prev,
          totalArea: farm.size ? parseFloat(farm.size) * 0.4047 : prev.totalArea,
          plantedArea: farm.size ? parseFloat(farm.size) * 0.4047 : prev.plantedArea,
          treeDensity: farm.recommendedCrops?.length ? 100 + farm.recommendedCrops.length * 20 : prev.treeDensity,
          ler: 1.2 + (farm.recommendedCrops?.length || 1) * 0.15,
          waterSavings: farm.irrigation === 'Drip' ? 80 : farm.irrigation === 'Rain-fed' ? 60 : prev.waterSavings,
          carbonSequestration: 2.0 + (farm.recommendedCrops?.length || 1) * 0.3,
          totalRevenue: 100000 + (farm.recommendedCrops?.length || 1) * 20000,
          roi: 25 + (farm.recommendedCrops?.length || 1) * 5,
          rootOverlapIndex: 0.2 + (farm.recommendedCrops?.length || 1) * 0.02,
          canopyCover: 80 + (farm.recommendedCrops?.length || 1) * 3,
        }));
      }
    }
  }, []);

  return (
    <PageLayout title="Farmer Dashboard">
      <div className="space-y-6">
        {/* Top row: Quick Stats + AI/ML Tools + Data Health */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* ML Quick Actions */}
          <motion.div 
            className="glass p-6"
            initial={{ opacity: 0, y: 20 }} 
            animate={{ opacity: 1, y: 0 }} 
            transition={{ delay: 0.1 }}
          >
            <h3 className="text-green-400 font-bold text-lg mb-4 flex items-center gap-2">
              <Cpu size={20} />
              AI/ML Tools
            </h3>
            <div className="space-y-3">
              <Link href="/predict" className="flex items-center gap-3 w-full px-4 py-3 rounded-xl bg-green-500/20 border border-green-500/30 text-green-400 font-medium hover:bg-green-500/30 transition-all">
                <TrendingUp size={18} />
                <span>Yield Prediction</span>
              </Link>
              <Link href="/optimize" className="flex items-center gap-3 w-full px-4 py-3 rounded-xl bg-purple-500/20 border border-purple-500/30 text-purple-400 font-medium hover:bg-purple-500/30 transition-all">
                <Cpu size={18} />
                <span>Strata Optimizer</span>
              </Link>
              <Link href="/calc" className="flex items-center gap-3 w-full px-4 py-3 rounded-xl bg-emerald-500/20 border border-emerald-500/30 text-emerald-400 font-medium hover:bg-emerald-500/30 transition-all">
                <Calculator size={18} />
                <span>Resource Calculator</span>
              </Link>
              <Link href="/crops" className="flex items-center gap-3 w-full px-4 py-3 rounded-xl bg-lime-500/10 border border-lime-500/30 text-lime-400 font-medium hover:bg-lime-500/20 transition-all">
                <Database size={18} />
                <span>Crops Database</span>
              </Link>
            </div>
          </motion.div>

          {/* Data Health - takes 2 columns on larger screens */}
          <motion.div 
            className="glass p-6 lg:col-span-2"
            initial={{ opacity: 0, y: 20 }} 
            animate={{ opacity: 1, y: 0 }} 
            transition={{ delay: 0.2 }}
          >
            <DataHealthWidget defaultFarmId="farm-001" />
          </motion.div>
        </div>

        {/* Farm Profile Summary Card */}
        {farmProfile && (
          <div className="glass p-4 rounded-xl border border-green-700/30 flex flex-col md:flex-row gap-4 items-center">
            <div className="flex-1">
              <div className="text-green-400 font-bold text-lg">{farmProfile.name || 'My Farm'}</div>
              <div className="text-green-200 text-sm">{farmProfile.location || ''}</div>
              <div className="text-green-200 text-sm">Soil: {farmProfile.soilType || ''}</div>
            </div>
            <div className="flex-1 flex flex-col gap-1">
              <div className="text-green-100 text-xs">Owner: {farmProfile.owner || ''}</div>
              <div className="text-green-100 text-xs">Region: {farmProfile.region || ''}</div>
              <div className="text-green-100 text-xs">Season: {farmProfile.season || ''}</div>
            </div>
          </div>
        )}

        {/* Full-width Metrics Dashboard */}
        <motion.div 
          className="glass p-6"
          initial={{ opacity: 0, y: 20 }} 
          animate={{ opacity: 1, y: 0 }} 
          transition={{ delay: 0.3 }}
        >
          <MetricsDashboard metrics={metrics} />
        </motion.div>
      </div>
    </PageLayout>
  );
}
